import{_ as s,M as a,p as c,q as n,Q as t,N as i,V as p,a1 as l,t as e}from"./framework-d7d41868.js";const d="/images/realize/基座请求模块.png",h={},u=l('<h1 id="请求概念篇" tabindex="-1"><a class="header-anchor" href="#请求概念篇" aria-hidden="true">#</a> 请求概念篇</h1><p>请求模块主要实现了如下功能：</p><ul><li>请求实例注册</li><li>请求拦截 <ul><li>请求头携带 token</li><li>登录过期跳转登录页</li></ul></li><li>响应拦截 <ul><li>登录过期处理</li><li>错误码处理</li><li>错误消息统一提示</li></ul></li><li>代理配置（跨域）</li><li>接口 api 快捷配置注册</li></ul><p>本章概念依旧是为想要学习请求封装的同学准备的</p>',4),_=e("框架内已对请求模块进行了高度封装，各位开发人员即使对内部封装不了解，知道如何去注册 api，如何"),b=e("使用 api "),x=e("也是可以正常开发的"),k=e("框架的请求工具使用的是 "),f={href:"http://www.axios-js.com/",target:"_blank",rel:"noopener noreferrer"},m=e("axios"),q=l('<p>基座应用的封装和微应用的实现不一样，微应用的属于简化版</p><h2 id="请求实例封装" tabindex="-1"><a class="header-anchor" href="#请求实例封装" aria-hidden="true">#</a> 请求实例封装</h2><h3 id="基座应用" tabindex="-1"><a class="header-anchor" href="#基座应用" aria-hidden="true">#</a> 基座应用</h3><p>模块内容如下：</p><p><img src="'+d+'" alt="基座请求模块"></p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>整个系统（基座应用，微应用）的请求模块核心都在这里</p></div><h4 id="index-ts" tabindex="-1"><a class="header-anchor" href="#index-ts" aria-hidden="true">#</a> index.ts</h4><ul><li>创建当前系统的 axios 实例</li><li>当前系统的配置传递</li><li>请求拦截器添加</li><li>响应拦截器添加</li><li>抛出实例</li></ul><h4 id="constant" tabindex="-1"><a class="header-anchor" href="#constant" aria-hidden="true">#</a> constant</h4><p><code>/src/http/constant/</code> 目录用来存放一些请求模块运行时的常量信息</p><p>内部已经包含一个 <code>excludeApis.ts</code> ，用来存放不需要验证登录的接口标识</p><h4 id="interceptors" tabindex="-1"><a class="header-anchor" href="#interceptors" aria-hidden="true">#</a> interceptors</h4><p>路由拦截器处理函数模块，之所以将拦截器的处理函数独立出来，是因为要统一拦截器的行为，抽取成模块，才能传递给微应用，以让微应用使用基座应用的拦截处理函数</p><ul><li><p>request.ts 请求拦截器处理函数</p><ul><li><ol><li>判断当期请求是否需要验证登录</li></ol><blockquote><p>否 -&gt; 放行；<br> 是 -&gt; 如下</p></blockquote></li><li><ol start="2"><li>添加 token 到请求头中，统一处理</li></ol></li><li><ol start="3"><li>验证登录是否超时或刷新（阻塞行为）</li></ol><blockquote><p>未超时 -&gt; 放行；<br> 刷新后 -&gt; 将刷新接口返回的新的 token 更新请求头中已添加的 token；<br> 超时 -&gt; 放弃请求，返回登录页</p></blockquote></li></ul></li><li><p>response.ts 响应拦截器处理函数</p><ul><li><ol><li>判断此次请求是否为业务请求（需要登录）</li></ol><blockquote><p>否 -&gt; 放行；<br> 是 -&gt; 如下</p></blockquote></li><li><ol start="2"><li>是否返回登录失效状态码</li></ol><blockquote><p>是 -&gt; 清空登录信息 + 返回登录页 + 消息提示（warning）；<br> 否 -&gt; 如下</p></blockquote></li><li><ol start="3"><li>请求是否成功（状态码 === &#39;000000&#39;）</li></ol><blockquote><p>否 -&gt; 返回结果 + 消息提示（error）；<br> 是 -&gt; 如下</p></blockquote></li><li><ol start="4"><li>返回响应体</li></ol></li></ul></li></ul><h4 id="proxys" tabindex="-1"><a class="header-anchor" href="#proxys" aria-hidden="true">#</a> proxys</h4><p>proxys 模块是用来配置代理的，将为 webpack 服务，为了统一请求模块，故将代理也放在了 <code>/src/http</code> 下</p><p>何为代理？</p><p>为了解决跨域问题，代理是通过我们开发模式下的本地开发服务器，作为中间服务器，进行代理转发的一个过程</p>',18),g=e("我们开发模式下，发送的请求实际上都是请求的本地开发服务器的，详细请参考 "),v={href:"https://cli.vuejs.org/zh/config/#devserver-proxy",target:"_blank",rel:"noopener noreferrer"},j=e("vue-cli devServer.proxy"),w=l('<p>代理模块内容，将被 webpack 静态加载，所以都要以 js 文件编写</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>基座应用在运行时，将微应用的资源加载到自己的端口下，进行解析渲染，就造成微应用中的请求实际上也是向基座应用的端口去请求的，所以，代理的配置都要由基座应用统一完成</p></div><ul><li><p>index.js</p><blockquote><p>统一抛出各应用的代理配置</p></blockquote></li><li><p>readEnvConfig.js</p><blockquote><p>属于工具类，读取 <code>/.env</code> 或 <code>/.env.local</code> 的默认代理 url 配置</p></blockquote></li><li><p>uums.js</p><blockquote><p>uums 系统的代理配置</p></blockquote></li><li><p>xxx.js</p></li></ul><h4 id="utils-ts" tabindex="-1"><a class="header-anchor" href="#utils-ts" aria-hidden="true">#</a> utils.ts</h4><p>http 模块的工具类</p><h3 id="微应用" tabindex="-1"><a class="header-anchor" href="#微应用" aria-hidden="true">#</a> 微应用</h3><p>微应用 http 的封装和基座应用的 <code>/src/http/index.ts</code> 功能一致，存放与 <code>/src/utils/http.ts</code></p>',7);function E(y,B){const r=a("RouterLink"),o=a("ExternalLinkIcon");return c(),n("div",null,[u,t("p",null,[_,i(r,{to:"/micro/moduleDetail/requestPractical.html#api-%E7%9A%84%E4%BD%BF%E7%94%A8"},{default:p(()=>[b]),_:1}),x]),t("p",null,[k,t("a",f,[m,i(o)])]),q,t("p",null,[g,t("a",v,[j,i(o)])]),w])}const N=s(h,[["render",E],["__file","requestConcept.html.vue"]]);export{N as default};
